package devmachine

import "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/util"

// 开发机状态常量
// 正常生命周期顺序：scheduling → pulling_image → initializing → starting → running
const (
	StatusScheduling   = "scheduling"   // 等待调度（Pod 未分配节点）
	StatusPullingImage = "pullingimage" // 拉取镜像中（已调度，容器尚未创建）
	StatusInitializing = "initializing" // Init 容器运行中
	StatusStarting     = "starting"     // 业务容器启动中（ContainerCreating 或 Running 但未 Ready）
	StatusRunning      = "running"      // 运行中（所有容器 Ready）

	StatusFailed           = "failed"           // 失败（ImagePullBackOff / CrashLoopBackOff / OOMKilled 等）
	StatusCrashLoopBackOff = "crashloopbackoff" // 开机失败（兼容旧值，新代码统一用 failed + reason 区分）
	StatusError            = "error"            // 通用错误状态
	StatusTerminating      = "terminating"      // 关机中（DeletionTimestamp 已设置）
	StatusStopped          = "stopped"          // 已关机（副本数为 0）

	StatusUnknown = "unknown" // 未知状态
)

type StatusEnumProvider struct{}

var EnumItemMap = map[string]string{
	StatusScheduling:       "等待调度",
	StatusPullingImage:     "拉取镜像",
	StatusInitializing:     "初始化中",
	StatusStarting:         "启动中",
	StatusRunning:          "运行中",
	StatusFailed:           "失败",
	StatusCrashLoopBackOff: "开机失败",
	StatusError:            "错误状态",
	StatusTerminating:      "关机中",
	StatusStopped:          "已关机",
	StatusUnknown:          "未知状态",
}

func (p *StatusEnumProvider) GetEnum() []util.EnumItem {
	orderedKeys := []string{
		StatusScheduling,
		StatusPullingImage,
		StatusInitializing,
		StatusStarting,
		StatusRunning,
		StatusFailed,
		StatusCrashLoopBackOff,
		StatusError,
		StatusTerminating,
		StatusStopped,
		StatusUnknown,
	}
	enumItems := make([]util.EnumItem, 0, len(orderedKeys))
	for _, key := range orderedKeys {
		if value, exists := EnumItemMap[key]; exists {
			enumItems = append(enumItems, util.EnumItem{
				Key:   key,
				Value: value,
			})
		}
	}
	return enumItems
}

