14		"code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/config"
15		devmachinemodel "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/internal/model/devmachine"
16		k8s "code.srdcloud.cn/TDP-PaaS/tap/tap-edu-backend/pkg/external/k8s"
17	)
18	
19	// Service 开发机服务接口
20	type Service interface {
21		CreatePod(ctx context.Context, pod *k8s.PodSpec) error
22		DeletePod(ctx context.Context, name string) error
23		GetPod(ctx context.Context, name string) (*k8s.PodInfo, error)
24		ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error)
25		GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error)
26	
27		CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error)
28		UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error)
29		DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error)
30		GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error)
31		ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error)
32		StartDevmachine(ctx context.Context, namespace, name string) error
33		StopDevmachine(ctx context.Context, namespace, name string) error
34		GetDevmachineStatus(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineStatusResponse, error)
35		CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error)
36	}
37	
38	type service struct {
39		k8sClient k8s.Client
40		config    *config.Config
41	}
42	
43	// NewService 创建开发机服务
44	func NewService(k8sClient k8s.Client, cfg *config.Config) Service {
45		// 初始化CSI配置
46		if err := SyncCSIConfigFromStorageClass(k8sClient); err != nil {
47			log.Printf("warning: failed to sync CSI config from storage class: %v", err)
48		}
49	
50		// 启动CSI配置同步循环
51		StartCSISyncLoop(k8sClient)
52	
53		// 启动Ingress URL同步循环
54		StartIngressURLSyncLoop(k8sClient)
55	
56		return &service{k8sClient: k8sClient, config: cfg}
57	}
58	
59	func (s *service) CreatePod(ctx context.Context, pod *k8s.PodSpec) error {
60		if err := ValidatePodRequest(pod.Name, pod.Image); err != nil {
61			return NewValidationError("pod.Name", pod.Name, err)
62		}
63		return s.k8sClient.CreatePod(ctx, pod)
64	}
65	
66	func (s *service) DeletePod(ctx context.Context, name string) error {
67		if err := ValidatePodName(name); err != nil {
68			return NewValidationError("pod.Name", name, err)
69		}
70		return s.k8sClient.DeletePod(ctx, name)
71	}
72	
73	func (s *service) GetPod(ctx context.Context, name string) (*k8s.PodInfo, error) {
74		if err := ValidatePodName(name); err != nil {
75			return nil, NewValidationError("pod.Name", name, err)
76		}
77		return s.k8sClient.GetPod(ctx, name)
78	}
79	
80	func (s *service) ListPods(ctx context.Context, labels map[string]string) ([]k8s.PodInfo, error) {
81		return s.k8sClient.ListPods(ctx, labels)
82	}
83	
84	func (s *service) GetPodLogs(ctx context.Context, name string, tailLines int64) (string, error) {
85		if err := ValidatePodName(name); err != nil {
86			return "", NewValidationError("pod.Name", name, err)
87		}
88		if tailLines <= 0 {
89			tailLines = 100
90		}
91		return s.k8sClient.GetPodLogs(ctx, name, tailLines)
92	}
93	
94	func (s *service) CreateDevmachine(ctx context.Context, request *devmachinemodel.CreateDevmachineRequest) (*devmachinemodel.CreateDevmachineResponse, error) {
95		// 验证请求参数
96		if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
97			return nil, NewValidationError("devmachine", request.Name, err)
98		}
99	
100		var err error
101	
102		defer func() {
103			if err != nil {
104				log.Printf("error: failed to create devmachine, try to cleanup: %v", err)
105				_, _ = s.DeleteDevmachine(ctx, request.Namespace, request.Name)
106			}
107		}()
108	
109		// 1. 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 补建）
110		// TODO: 新环境稳定后可移除此兼容逻辑
111		if len(request.Storage) > 0 {
112			if err = s.ensureSharedPVCs(ctx, request.Namespace, request.Storage); err != nil {
113				return nil, err
114			}
115		}
116	
117		// 3. 创建 Deployment
118		deployment := generateDevMachineDeployment(request, s.config.InitContainer.Image)
119		if err := s.k8sClient.CreateDeployment(ctx, deployment); err != nil {
120			return nil, NewResourceError("Deployment", request.Name, "create", err)
121		}
122	
123		// 3. 创建 Service
124		service := generateDevMachineService(request)
125		if err := s.k8sClient.CreateService(ctx, service); err != nil {
126			return nil, NewResourceError("Service", request.Name+serviceSuffix, "create", err)
127		}
128	
129		// 4. 创建 Ingress
130		ingress := generateDevMachineIngress(request)
131		if err := s.k8sClient.CreateIngress(ctx, ingress); err != nil {
132			return nil, NewResourceError("Ingress", request.Name+ingressSuffix, "create", err)
133		}
134	
135		return &devmachinemodel.CreateDevmachineResponse{
136			Name:   request.Name,
137			Status: "pending",
138			WebUrl: fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(request.Namespace, request.Name)),
139		}, nil
140	}
141	
142	func (s *service) UpdateDevmachine(ctx context.Context, request *devmachinemodel.UpdateDevmachineRequest) (*devmachinemodel.UpdateDevmachineResponse, error) {
143		// 验证请求参数
144		if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
145			return nil, NewValidationError("devmachine", request.Name, err)
146		}
147	
148		// 1. 获取现有 Deployment
149		deployment, err := s.k8sClient.GetDeployment(ctx, request.Namespace, request.Name)
150		if err != nil {
151			return nil, NewResourceError("Deployment", request.Name, "get", err)
152		}
153	
154		// 2. 更新 Deployment 配置
155		deployment.Spec.Template.Spec.Containers[0].Image = request.ImageName
156	
157		// 更新资源请求
158		if request.CPU != "" || request.Memory != "" || request.GPU != "" {
159			// 构建新的资源请求
160			resources := BuildResourceRequirements(request.CPU, request.Memory, request.GPU, request.GPUName)
161			deployment.Spec.Template.Spec.Containers[0].Resources = resources
162		}
163	
164		// 更新节点选择器
165		if len(request.NodeSelector) > 0 {
166			deployment.Spec.Template.Spec.NodeSelector = request.NodeSelector
167		}
168	
169		// 更新标签
170		if len(request.Labels) > 0 {
171			for k, v := range request.Labels {
172				deployment.Labels[k] = v
173				deployment.Spec.Template.Labels[k] = v
174			}
175		}
176	
177		// 更新注解
178		if len(request.Annotations) > 0 {
179			for k, v := range request.Annotations {
180				deployment.Annotations[k] = v
181				deployment.Spec.Template.Annotations[k] = v
182			}
183		}
184	
185		// 更新队列名称
186		if request.QueueName != "" {
187			deployment.Spec.Template.Annotations[volcanoQueueName] = request.QueueName
188		}
189	
190		// 3. 更新 Deployment
191		if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
192			return nil, NewResourceError("Deployment", request.Name, "update", err)
193		}
194	
195		// 返回更新时间
196		return &devmachinemodel.UpdateDevmachineResponse{
197			UpdateAt: time.Now().Format(time.RFC3339),
198		}, nil
199	}
200	
201	func (s *service) DeleteDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.DeleteDevmachineResponse, error) {
202		// 1. 删除 Ingress
203		if err := s.k8sClient.DeleteIngress(ctx, namespace, name+ingressSuffix); err != nil {
204			// 记录错误但继续删除其他资源
205			log.Printf("warning: failed to delete ingress: %v\n", err)
206		}
207	
208		// 2. 删除 Service
209		if err := s.k8sClient.DeleteService(ctx, namespace, name+serviceSuffix); err != nil {
210			log.Printf("warning: failed to delete service: %v\n", err)
211		}
212	
213		// 3. 删除 Deployment
214		if err := s.k8sClient.DeleteDeployment(ctx, namespace, name); err != nil {
215			log.Printf("warning: failed to delete deployment: %v\n", err)
216		}
217	
218		// PVC 和 PV 为共享资源，随 namespace 生命周期管理，不随开发机删除
219	
220		// 返回删除时间
221		return &devmachinemodel.DeleteDevmachineResponse{
222			DeleteAt: time.Now().Format(time.RFC3339),
223		}, nil
224	}
225	
226	func (s *service) GetDevmachine(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineResponse, error) {
227		// 验证请求参数
228		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
229			return nil, NewValidationError("devmachine", name, err)
230		}
231	
232		// 获取 Deployment 信息
233		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
234		if err != nil {
235			return nil, NewResourceError("Deployment", name, "get", err)
236		}
237	
238		// 获取 Service 信息
239		service, err := s.k8sClient.GetService(ctx, namespace, name+serviceSuffix)
240		if err != nil {
241			return nil, NewResourceError("Service", name+serviceSuffix, "get", err)
242		}
243	
244		// 获取 Ingress 信息
245		ingress, err := s.k8sClient.GetIngress(ctx, namespace, name+ingressSuffix)
246		if err != nil {
247			return nil, NewResourceError("Ingress", name+ingressSuffix, "get", err)
248		}
249	
250		if deployment == nil || service == nil || ingress == nil {
251			return nil, fmt.Errorf("deployment or service or ingress not found")
252		}
253	
254		// 获取与Deployment关联的存储信息（从 volumeMounts 的 subPath 读取，共享PVC模式）
255		var storage []devmachinemodel.Storage
256		if len(deployment.Spec.Template.Spec.Containers) > 0 {
257			container := deployment.Spec.Template.Spec.Containers[0]
258			for _, vm := range container.VolumeMounts {
259				if vm.Name == SharedRWVolumeName || vm.Name == SharedROVolumeName {
260					storage = append(storage, devmachinemodel.Storage{
261						MountPath:   vm.MountPath,
262						StoragePath: vm.SubPath,
263						ReadOnly:    vm.ReadOnly,
264					})
265				}
266			}
267		}
268	
269		// 提取 GPU 信息
270		gpu := "0"
271		gpuName := ""
272		if len(deployment.Spec.Template.Spec.Containers) > 0 {
273			container := deployment.Spec.Template.Spec.Containers[0]
274			if gpuResource, exists := container.Resources.Requests["hygon.com/dcu"]; exists {
275				gpu = gpuResource.String()
276				gpuName = "hygon.com/dcu"
277			} else if gpuResource, exists := container.Resources.Requests["nvidia.com/gpu"]; exists {
278				gpu = gpuResource.String()
279				gpuName = "nvidia.com/gpu"
280			}
281		}
282	
283		// 获取 WebIDE 类型
284		webIDE := GetWebIDEType(deployment)
285	
286		// 构建响应
287		response := &devmachinemodel.GetDevmachineResponse{
288			Devmachine: devmachinemodel.Devmachine{
289				Namespace:   deployment.Namespace,
290				Name:        deployment.Name,
291				QueueName:   deployment.Spec.Template.Annotations[volcanoQueueName],
292				ImageName:   deployment.Spec.Template.Spec.Containers[0].Image,
293				CPU:         deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Cpu().String(),
294				Memory:      deployment.Spec.Template.Spec.Containers[0].Resources.Requests.Memory().String(),
295				GPU:         gpu,
296				GPUName:     gpuName,
297				WebIDE:      webIDE,
298				WebUrl:      fmt.Sprintf("http://%s", GlobalIngressURL+BuildIngressPath(namespace, name)),
299				Storage:     storage,
300				Annotations: deployment.Annotations,
301				Labels:      deployment.Labels,
302			},
303		}
304	
305		// 填充 Pod 级别的细粒度状态
306		status, reason, message, ready, podName := s.resolveStatus(ctx, namespace, deployment)
307		response.Devmachine.Status = status
308		response.Devmachine.Reason = reason
309		response.Devmachine.Message = message
310		response.Devmachine.Ready = ready
311		response.Devmachine.PodName = podName
312	
313		return response, nil
314	}
315	
316	// resolveStatus 查询 Pod 并推导开发机当前所处的生命周期状态，供 GetDevmachine 和 GetDevmachineStatus 共用
317	func (s *service) resolveStatus(ctx context.Context, namespace string, deployment *appsv1.Deployment) (status, reason, message string, ready bool, podName string) {
318		// 副本数为 0，开发机已停止
319		if deployment.Spec.Replicas != nil && *deployment.Spec.Replicas == 0 {
320			return devmachinemodel.StatusStopped, "", "开发机已停止", false, ""
321		}
322	
323		// 通过 Deployment 的标签选择器查询对应的 Pod
324		if deployment.Spec.Selector == nil {
325			return devmachinemodel.StatusScheduling, "", "等待 Pod 创建", false, ""
326		}
327		pods, err := s.k8sClient.GetPodsByLabelSelector(ctx, namespace, deployment.Spec.Selector.MatchLabels)
328		if err != nil || len(pods) == 0 {
329			// Pod 尚未创建（Deployment 刚下发，controller 还未生成 Pod）
330			return devmachinemodel.StatusScheduling, "", "等待 Pod 创建", false, ""
331		}
332	
333		// 取最新创建的 Pod 作为当前状态来源
334		pod := getLatestPod(pods)
335		status, reason, message, ready = getStatusFromPod(pod)
336		return status, reason, message, ready, pod.Name
337	}
338	
339	func (s *service) ListDevmachines(ctx context.Context, devmachines []devmachinemodel.DevmachineName) ([]devmachinemodel.Devmachine, error) {
340		// 如果没有指定任何devmachine，则返回空列表
341		if len(devmachines) == 0 {
342			return []devmachinemodel.Devmachine{}, nil
343		}
344	
345		// 初始化结果切片
346		results := make([]devmachinemodel.Devmachine, len(devmachines))
347		errors := make([]error, len(devmachines))
348	
349		// 定义工作函数
350		workerFunc := func(piece int) {
351			// 获取指定的devmachine
352			devmachine := devmachines[piece]
353			// 调用GetDevmachine获取详细信息
354			result, err := s.GetDevmachine(ctx, devmachine.Namespace, devmachine.Name)
355			if err != nil {
356				errors[piece] = err
357			} else {
358				results[piece] = result.Devmachine
359			}
360		}
361	
362		// 使用workqueue.ParallelizeUntil进行并行处理
363		// 限制最大并发数以避免对k8s API服务器造成过大压力
364		maxWorkers := 10
365		workqueue.ParallelizeUntil(ctx, maxWorkers, len(devmachines), workerFunc)
366	
367		// 收集成功的结果
368		var successfulResults []devmachinemodel.Devmachine
369		for i, err := range errors {
370			if err == nil {
371				successfulResults = append(successfulResults, results[i])
372			} else {
373				log.Printf("warning: failed to get devmachine %s/%s: %v", devmachines[i].Namespace, devmachines[i].Name, err)
374			}
375		}
376	
377		return successfulResults, nil
378	}
379	
380	func (s *service) StartDevmachine(ctx context.Context, namespace, name string) error {
381		// 验证请求参数
382		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
383			return NewValidationError("devmachine", name, err)
384		}
385	
386		// 获取 Deployment
387		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
388		if err != nil {
389			return NewResourceError("Deployment", name, "get", err)
390		}
391	
392		// 设置 replicas 为 1
393		deployment.Spec.Replicas = ptr.To[int32](1)
