397			return NewResourceError("Deployment", name, "update", err)
398		}
399	
400		return nil
401	}
402	
403	func (s *service) StopDevmachine(ctx context.Context, namespace, name string) error {
404		// 验证请求参数
405		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
406			return NewValidationError("devmachine", name, err)
407		}
408	
409		// 获取 Deployment
410		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
411		if err != nil {
412			return NewResourceError("Deployment", name, "get", err)
413		}
414	
415		// 设置 replicas 为 0
416		deployment.Spec.Replicas = ptr.To[int32](0)
417	
418		// 更新 Deployment
419		if err := s.k8sClient.UpdateDeployment(ctx, deployment); err != nil {
420			return NewResourceError("Deployment", name, "update", err)
