425	
426	func (s *service) GetDevmachineStatus(ctx context.Context, namespace, name string) (*devmachinemodel.GetDevmachineStatusResponse, error) {
427		// 验证请求参数
428		if err := ValidateDevmachineRequest(name, namespace, ""); err != nil && namespace != "" && name != "" {
429			return nil, NewValidationError("devmachine", name, err)
430		}
431	
432		// 获取 Deployment 信息
433		deployment, err := s.k8sClient.GetDeployment(ctx, namespace, name)
434		if err != nil {
435			return nil, NewResourceError("Deployment", name, "get", err)
436		}
437	
438		// 与 GetDevmachine 使用同一套 Pod 级别状态推导逻辑
439		status, reason, message, ready, podName := s.resolveStatus(ctx, namespace, deployment)
440	
441		return &devmachinemodel.GetDevmachineStatusResponse{
442			Namespace: namespace,
443			Name:      name,
444			Status:    status,
445			Ready:     ready,
446			Reason:    reason,
447			Message:   message,
448			PodName:   podName,
449		}, nil
450	}
451	
452	// getLatestPod 从多个 Pod 中取创建时间最晚的一个（滚动更新时可能存在多个 Pod）
453	func getLatestPod(pods []*corev1.Pod) *corev1.Pod {
454		latest := pods[0]
455		for _, pod := range pods[1:] {
456			if pod.CreationTimestamp.After(latest.CreationTimestamp.Time) {
457				latest = pod
458			}
459		}
460		return latest
461	}
462	
463	// getStatusFromPod 根据 Pod 的实时状态推导开发机所处的生命周期状态
464	// 生命周期：scheduling → pullingimage → initializing → starting → running
465	func getStatusFromPod(pod *corev1.Pod) (status, reason, message string, ready bool) {
466		// Pod 正在被删除
467		if pod.DeletionTimestamp != nil {
468			return devmachinemodel.StatusTerminating, "", "开发机正在关闭", false
469		}
470	
471		switch pod.Status.Phase {
472		case corev1.PodPending:
473			return getPendingStatusDetail(pod)
474		case corev1.PodRunning:
475			return getRunningStatusDetail(pod)
476		case corev1.PodFailed:
477			return devmachinemodel.StatusFailed, pod.Status.Reason, pod.Status.Message, false
478		case corev1.PodSucceeded:
479			return devmachinemodel.StatusStopped, "", "容器已正常退出", false
480		default:
481			return devmachinemodel.StatusUnknown, "", "", false
482		}
483	}
484	
485	// getPendingStatusDetail 细化 Pending 阶段的具体状态
486	func getPendingStatusDetail(pod *corev1.Pod) (status, reason, message string, ready bool) {
487		// 1. 检查是否已完成调度
488		for _, cond := range pod.Status.Conditions {
489			if cond.Type == corev1.PodScheduled && cond.Status != corev1.ConditionTrue {
490				return devmachinemodel.StatusScheduling, cond.Reason, cond.Message, false
491			}
492		}
493	
494		// 2. 检查 Init 容器状态（Init 容器按序执行，逐个检查）
495		for i, cs := range pod.Status.InitContainerStatuses {
496			if cs.State.Terminated != nil && cs.State.Terminated.ExitCode != 0 {
497				return devmachinemodel.StatusFailed, cs.State.Terminated.Reason,
498					fmt.Sprintf("Init容器 %s 执行失败: %s", cs.Name, cs.State.Terminated.Message), false
499			}
500			if cs.State.Running != nil {
501				total := len(pod.Spec.InitContainers)
502				return devmachinemodel.StatusInitializing, "",
503					fmt.Sprintf("Init容器运行中 (%d/%d): %s", i+1, total, cs.Name), false
504			}
505			if cs.State.Waiting != nil {
506				r := cs.State.Waiting.Reason
507				switch r {
508				case "ErrImagePull", "ImagePullBackOff":
509					return devmachinemodel.StatusFailed, r,
510						fmt.Sprintf("Init容器 %s 镜像拉取失败: %s", cs.Name, cs.State.Waiting.Message), false
511				default:
512					return devmachinemodel.StatusInitializing, r,
513						fmt.Sprintf("Init容器 %s 等待中", cs.Name), false
514				}
515			}
516		}
517	
518		// 3. 检查主容器状态
519		for _, cs := range pod.Status.ContainerStatuses {
520			if cs.State.Waiting != nil {
521				r := cs.State.Waiting.Reason
522				switch r {
523				case "ErrImagePull", "ImagePullBackOff":
524					return devmachinemodel.StatusFailed, r, "镜像拉取失败: " + cs.State.Waiting.Message, false
525				case "CrashLoopBackOff":
526					return devmachinemodel.StatusFailed, r, "容器反复崩溃重启", false
527				case "ContainerCreating":
528					return devmachinemodel.StatusStarting, r, "容器启动中", false
529				default:
530					msg := cs.State.Waiting.Message
531					if msg == "" {
532						msg = "容器等待中"
533					}
534					return devmachinemodel.StatusStarting, r, msg, false
535				}
536			}
537		}
538	
539		// 已调度但尚无容器状态，说明还在拉取镜像
540		return devmachinemodel.StatusPullingImage, "", "拉取镜像中", false
541	}
542	
543	// getRunningStatusDetail 细化 Running 阶段的具体状态（容器可能还未 Ready）
544	func getRunningStatusDetail(pod *corev1.Pod) (status, reason, message string, ready bool) {
545		for _, cs := range pod.Status.ContainerStatuses {
546			if cs.State.Waiting != nil {
547				r := cs.State.Waiting.Reason
548				if r == "CrashLoopBackOff" {
549					return devmachinemodel.StatusFailed, r, "容器反复崩溃重启", false
550				}
551				return devmachinemodel.StatusStarting, r, "容器启动中", false
552			}
553			if cs.State.Terminated != nil {
554				r := cs.State.Terminated.Reason
555				if r == "OOMKilled" {
556					return devmachinemodel.StatusFailed, r, "容器内存不足被终止 (OOMKilled)", false
557				}
558				return devmachinemodel.StatusFailed, r, cs.State.Terminated.Message, false
559			}
560			if !cs.Ready {
561				return devmachinemodel.StatusStarting, "", "容器就绪检查中", false
562			}
563		}
564		if len(pod.Status.ContainerStatuses) == 0 {
565			return devmachinemodel.StatusStarting, "", "容器启动中", false
566		}
567		return devmachinemodel.StatusRunning, "", "运行中", true
568	}
569	
570	// sharedRWPVName 返回 namespace 级别读写 PV 的名称
571	func sharedRWPVName(namespace string) string {
572		return "shared-rw-pv-" + namespace
573	}
574	
575	// sharedROPVName 返回 namespace 级别只读 PV 的名称
576	func sharedROPVName(namespace string) string {
577		return "shared-ro-pv-" + namespace
578	}
579	
580	// ensureSharedPVCs 兼容兜底：确保 namespace 下共享 PV+PVC 存在（历史 namespace 补建）
581	// TODO: 新环境稳定后可移除
582	func (s *service) ensureSharedPVCs(ctx context.Context, namespace string, storages []devmachinemodel.Storage) error {
583		needsRW, needsRO := false, false
584		for _, st := range storages {
585			if st.ReadOnly {
586				needsRO = true
587			} else {
588				needsRW = true
589			}
590		}
591	
592		if needsRW {
593			if err := s.ensurePVCExists(ctx, namespace, SharedRWPVCName, sharedRWPVName(namespace), false); err != nil {
594				return err
595			}
596		}
597		if needsRO {
598			if err := s.ensurePVCExists(ctx, namespace, SharedROPVCName, sharedROPVName(namespace), true); err != nil {
599				return err
600			}
601		}
602		return nil
603	}
604	
605	// ensurePVCExists 检查 PVC 是否存在，不存在则先创建对应 PV 再创建 PVC
606	func (s *service) ensurePVCExists(ctx context.Context, namespace, pvcName, pvName string, readOnly bool) error {
607		exists, err := s.k8sClient.PVCExists(ctx, namespace, pvcName)
608		if err != nil {
609			return fmt.Errorf("check PVC %s/%s: %w", namespace, pvcName, err)
610		}
611		if !exists {
612			pvExists, err := s.k8sClient.PVExists(ctx, pvName)
613			if err != nil {
614				return fmt.Errorf("check PV %s: %w", pvName, err)
615			}
616			if !pvExists {
617				log.Printf("[compat] shared PV %s not found, creating...", pvName)
618				pv, err := buildSharedPV(pvName, namespace, readOnly)
619				if err != nil {
620					return fmt.Errorf("build PV %s: %w", pvName, err)
621				}
622				if err := s.k8sClient.CreatePV(ctx, pv); err != nil {
623					return fmt.Errorf("create PV %s: %w", pvName, err)
624				}
625			}
626			log.Printf("[compat] shared PVC %s not found in namespace %s, creating...", pvcName, namespace)
627			return s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, pvcName, pvName, readOnly))
628		}
629		return nil
630	}
631	
632	// createSharedPVCs 为 namespace 创建专属的读写和只读 PV+PVC
633	func (s *service) createSharedPVCs(ctx context.Context, namespace string) error {
634		rwPVName := sharedRWPVName(namespace)
635		rwPV, err := buildSharedPV(rwPVName, namespace, false)
636		if err != nil {
637			return fmt.Errorf("build shared-rw-pv for %s: %w", namespace, err)
638		}
639		if err := s.k8sClient.CreatePV(ctx, rwPV); err != nil {
640			return fmt.Errorf("create shared-rw-pv for %s: %w", namespace, err)
641		}
642		if err := s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, SharedRWPVCName, rwPVName, false)); err != nil {
643			return fmt.Errorf("create shared-rw-pvc in %s: %w", namespace, err)
644		}
645	
646		roPVName := sharedROPVName(namespace)
647		roPV, err := buildSharedPV(roPVName, namespace, true)
648		if err != nil {
649			return fmt.Errorf("build shared-ro-pv for %s: %w", namespace, err)
650		}
651		if err := s.k8sClient.CreatePV(ctx, roPV); err != nil {
652			return fmt.Errorf("create shared-ro-pv for %s: %w", namespace, err)
653		}
654		if err := s.k8sClient.CreatePVC(ctx, buildSharedPVC(namespace, SharedROPVCName, roPVName, true)); err != nil {
655			return fmt.Errorf("create shared-ro-pvc in %s: %w", namespace, err)
656		}
657	
658		return nil
659	}
660	
661	func (s *service) CreateNamespace(ctx context.Context, request *devmachinemodel.CreateNamespaceRequest) (*devmachinemodel.CreateNamespaceResponse, error) {
662		// 验证请求参数
663		if request.Namespace == "" {
664			return nil, NewValidationError("namespace", request.Namespace, fmt.Errorf("namespace cannot be empty"))
665		}
666	
667		// 创建命名空间
668		if err := s.k8sClient.CreateNamespace(ctx, request.Namespace); err != nil {
669			return nil, NewResourceError("Namespace", request.Namespace, "create", err)
670		}
671	
672		// 为新 namespace 创建共享 PVC
673		if err := s.createSharedPVCs(ctx, request.Namespace); err != nil {
674			log.Printf("warning: failed to create shared PVCs in namespace %s: %v", request.Namespace, err)
675			// 注意：PVC 创建失败不影响 namespace 创建的成功响应，兼容兜底会在首次创建开发机时补建
676		}
677	
678		return &devmachinemodel.CreateNamespaceResponse{
679			Message: fmt.Sprintf("namespace %s created successfully", request.Namespace),
680		}, nil
681	}
